import { StyleSheet, Text, View, Image , TextInput, ScrollView} from 'react-native';
import React from 'react';

export default function App() {
  const [number, onChangeNumber] = React.useState('');
  const [anoNascimento, setAnoNascimento] = React.useState('');
    const calcularAnoNascimento = (idade: string) => {

    const idadeNumero = parseInt(idade);
    if (!isNaN(idadeNumero)) {
      const anoAtual = new Date().getFullYear();
      const nascimento = anoAtual - idadeNumero;
      setAnoNascimento(nascimento.toString());
    } else {
      setAnoNascimento('');
    }
  };
 //Verificar o contentContainerStyle para o ScrollView para deixar no centro , entre outras coisas. Colocar o ScrollView fora do View, para testar, além de ser a forma correta.
return (
  
    <View style={styles.perfil}>
    <ScrollView>
      <Image
        source={require('../assets/images/Imagem_Bio.png')}
        style={styles.foto_perfil}
        resizeMode="cover"
      />

      <View style={styles.bio}>
        <Text style={{fontSize: 40}}>Lucas Mendes Nóbrega</Text>

        <Text style={{fontSize: 20}}>
          Sou estudante de Ciência da Computação, atualmente no 5º período, com sólida base 
          em programação e forte interesse em desenvolvimento de software e engenharia de 
          sistemas. Participo ativamente de projetos acadêmicos que envolvem Java, Python 
          e C, aplicando conceitos de Programação Orientada a Objetos, estruturas de dados, 
          análise sintática e arquitetura de software.
        </Text>

        <Text style={{fontSize: 20}}>
          Tenho perfil analítico e gosto de enfrentar desafios lógicos, sempre buscando soluções 
          eficientes e criativas. Entre minhas principais habilidades estão resolução de problemas, 
          pensamento crítico, aprendizagem rápida e aplicação de boas práticas de desenvolvimento.
        </Text>

        <Text style={{fontSize: 20}}>
          Busco oportunidades para colocar em prática meus conhecimentos, evoluir profissionalmente 
          e contribuir para projetos que tragam impacto real, aliando tecnologia a inovação.
        </Text>
        <View style={styles.hr} />  
      </View>
      <View>
        <TextInput
          style={styles.input}
          onChangeText={(Text) =>{
              onChangeNumber(Text);
              calcularAnoNascimento(Text);
          }}
          value={number}
          placeholder="Digite a sua idade"
          keyboardType="numeric"
        />
        <Text>Você nasceu em</Text>
          <TextInput 
            style={styles.input}
            readOnly
            value={anoNascimento}
          />
      </View>
      </ScrollView>
    </View>
  
  )}

const styles = StyleSheet.create({
  perfil: {
    flex: 1,
    justifyContent: 'center',
    gap: 60,
    alignItems: "center",
  },

  foto_perfil: {
    width: 250,
    height: 250,
    borderRadius: 125,
    
  },
  bio: {
    width: "99%",
    justifyContent: 'center',
  },
  input: {
    height: 40,
    margin: 12,
    borderWidth: 1,
    padding: 10,
  },
  hr: {
    height: 2, backgroundColor: 'black', flex: 0.9,
  }
});
